import{_ as e,o as a,c as o,a3 as r}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Legal Notices","description":"","frontmatter":{"title":"Legal Notices"},"headers":[],"relativePath":"en/advertisers/sponsored-mail/design-guide/legal.md","filePath":"en/advertisers/sponsored-mail/design-guide/legal.md"}'),s={name:"en/advertisers/sponsored-mail/design-guide/legal.md"};function n(i,t,l,d,g,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="legal-notices-logos" tabindex="-1">Legal Notices &amp; Logos <a class="header-anchor" href="#legal-notices-logos" aria-label="Permalink to &quot;Legal Notices &amp; Logos&quot;">​</a></h1><p>Any printed advertising engages your responsibility. These elements are mandatory on every flyer — their absence blocks Proof (BAT) validation.</p><hr><h2 id="universal-notices" tabindex="-1">Universal Notices <a class="header-anchor" href="#universal-notices" aria-label="Permalink to &quot;Universal Notices&quot;">​</a></h2><p>These 3 blocks apply to <strong>all advertisers</strong>, regardless of the sector.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Advertiser Identification</strong><p>Corporate name · Legal form · Share capital · Head office address · RCS number + registration city</p><p><em>Example: &quot;ACME SAS with a capital of 10,000€ — 12 rue de la Paix, 75001 Paris — RCS Paris 123 456 789&quot;</em></p></div><div class="gi-value-card"><strong>2. Environmental Logos</strong><p><strong>Sorting Info Cartouche (Triman)</strong> — minimum size 8 mm. Mandatory since the AGEC Law.</p><p><strong>getinside Logo</strong> — provided with the templates.</p><p><a href="https://drive.google.com/drive/folders/1ORm6uAhsIWCCFWhOl-NjO4tKfiGQdLNy" target="_blank">⬇️ Download the Logos pack</a></p></div><div class="gi-value-card"><strong>3. Offer T&amp;Cs</strong><p>Offer validity dates · Special conditions (e.g., &quot;valid from 50€ purchase&quot;) · Any usage restrictions</p></div></div><hr><h2 id="sectoral-notices" tabindex="-1">Sectoral Notices <a class="header-anchor" href="#sectoral-notices" aria-label="Permalink to &quot;Sectoral Notices&quot;">​</a></h2><p>If your activity falls under one of the sectors below, the corresponding notice is <strong>mandatory</strong> on your flyer.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Sector</th><th style="text-align:left;">Mandatory notice</th><th style="text-align:left;">Legal reference</th></tr></thead><tbody><tr><td style="text-align:left;">🍷 <strong>Alcohol</strong></td><td style="text-align:left;"><em>&quot;L&#39;abus d&#39;alcool est dangereux pour la santé, à consommer avec modération.&quot;</em> (Alcohol abuse is dangerous for health, consume with moderation) + Ban on targeting minors</td><td style="text-align:left;">Evin Law — Art. L3323-4</td></tr><tr><td style="text-align:left;">🥗 <strong>Food</strong></td><td style="text-align:left;"><em>&quot;Pour votre santé, mangez au moins cinq fruits et légumes par jour.&quot;</em> (For your health, eat at least five fruits and vegetables a day)</td><td style="text-align:left;">Art. L2133-1 CSP — mangerbouger.fr</td></tr><tr><td style="text-align:left;">🚗 <strong>Automotive</strong></td><td style="text-align:left;">Energy class (l/100km and g CO2/km) + <em>&quot;Pensez à covoiturer.&quot;</em> (Think about carpooling)</td><td style="text-align:left;">Decree of January 10, 2018</td></tr><tr><td style="text-align:left;">💰 <strong>Credit / Finance</strong></td><td style="text-align:left;"><em>&quot;Un crédit vous engage et doit être remboursé. Vérifiez vos capacités de remboursement avant de vous engager.&quot;</em> (A credit commits you and must be repaid. Check your repayment capacity before committing.)</td><td style="text-align:left;">Art. L311-5 Consumer Code</td></tr><tr><td style="text-align:left;">🎰 <strong>Gambling</strong></td><td style="text-align:left;"><em>&quot;Jouer comporte des risques : endettement, isolement, dépendance. Appelez le 09-74-75-13-13 (appel non surtaxé).&quot;</em> (Playing involves risks: debt, isolation, addiction...) + Ban on targeting minors</td><td style="text-align:left;">ANJ — Law of May 12, 2010</td></tr><tr><td style="text-align:left;">💊 <strong>Medication / Parapharmacy</strong></td><td style="text-align:left;"><em>&quot;Lire attentivement la notice. Demandez conseil à votre médecin ou pharmacien.&quot;</em> (Read the leaflet carefully. Ask your doctor or pharmacist for advice.)</td><td style="text-align:left;">Public Health Code</td></tr><tr><td style="text-align:left;">🧸 <strong>Toys</strong></td><td style="text-align:left;">Indication of recommended age (e.g., <em>&quot;3+&quot;</em>) + <em>&quot;Ne convient pas aux enfants de moins de 3 ans.&quot;</em> (Not suitable for children under 3 years.)</td><td style="text-align:left;">Directive 2009/48/EC</td></tr><tr><td style="text-align:left;">🛡️ <strong>Insurance</strong></td><td style="text-align:left;"><em>&quot;Un contrat d&#39;assurance vous engage et doit être respecté. Vérifiez les termes avant de vous engager.&quot;</em> (An insurance contract commits you and must be respected. Check the terms before committing.)</td><td style="text-align:left;">Insurance Code</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">In case of doubt</p><p>If your sector is not listed or if you hesitate on the exact wording, send your Proof to <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a> before printing — our team validates legal compliance.</p></div>',11)])])}const f=e(s,[["render",n]]);export{m as __pageData,f as default};
